class Solution:
    def countPaths(self, n, roads):
        MOD = 10**9 + 7
        INF = float('inf')
        adj = [[] for _ in range(n)]
        for u, v, w in roads:
            adj[u].append((v, w))
            adj[v].append((u, w))
        dist = [INF] * n
        ways = [0] * n
        done = [False] * n
        dist[0] = 0
        ways[0] = 1
        for _ in range(n):
            u = -1
            best = INF
            for i in range(n):
                if not done[i] and dist[i] < best:
                    best = dist[i]
                    u = i
            if u == -1:
                break
            done[u] = True
            for v, w in adj[u]:
                nd = dist[u] + w
                if nd < dist[v]:
                    dist[v] = nd
                    ways[v] = ways[u]
                elif nd == dist[v]:
                    ways[v] = (ways[v] + ways[u]) % MOD
        return ways[n - 1] % MOD

